212: private:
213:   GrpcStatusHashSet statuses_;
214:   bool exclude_;
215: 
216:   /**
217:    * Converts a Protobuf representation of a gRPC status into the equivalent code version of a gRPC
218:    * status.
219:    */
220:   Grpc::Status::GrpcStatus
221:   protoToGrpcStatus(envoy::config::accesslog::v3::GrpcStatusFilter::Status status) const;
