23: // Custom configuration for an :ref:`AccessLog <envoy_v3_api_msg_config.accesslog.v3.AccessLog>`
24: // that writes log entries directly to a file. Configures the built-in ``envoy.access_loggers.file``
25: // AccessLog.
26: // [#next-free-field: 6]
27: message FileAccessLog {
28:   option (udpa.annotations.versioning).previous_message_type =
29:       "envoy.config.accesslog.v2.FileAccessLog";
30: 
31:   // A path to a local file to which to write the access log entries.
32:   string path = 1 [(validate.rules).string = {min_len: 1}];
33: 
34:   oneof access_log_format {
35:     // Access log :ref:`format string<config_access_log_format_strings>`.
36:     // Envoy supports :ref:`custom access log formats <config_access_log_format>` as well as a
37:     // :ref:`default format <config_access_log_default_format>`.
38:     // This field is deprecated.
39:     // Please use :ref:`log_format <envoy_v3_api_field_extensions.access_loggers.file.v3.FileAccessLog.log_format>`.
40:     string format = 2 [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
41: 
42:     // Access log :ref:`format dictionary<config_access_log_format_dictionaries>`. All values
43:     // are rendered as strings.
44:     // This field is deprecated.
45:     // Please use :ref:`log_format <envoy_v3_api_field_extensions.access_loggers.file.v3.FileAccessLog.log_format>`.
46:     google.protobuf.Struct json_format = 3
47:         [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
48: 
49:     // Access log :ref:`format dictionary<config_access_log_format_dictionaries>`. Values are
50:     // rendered as strings, numbers, or boolean values as appropriate. Nested JSON objects may
51:     // be produced by some command operators (e.g.FILTER_STATE or DYNAMIC_METADATA). See the
52:     // documentation for a specific command operator for details.
53:     // This field is deprecated.
54:     // Please use :ref:`log_format <envoy_v3_api_field_extensions.access_loggers.file.v3.FileAccessLog.log_format>`.
55:     google.protobuf.Struct typed_json_format = 4
56:         [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
57: 
58:     // Configuration to form access log data and format.
59:     // If not specified, use :ref:`default format <config_access_log_default_format>`.
60:     config.core.v3.SubstitutionFormatString log_format = 5
61:         [(validate.rules).message = {required: true}];
62:   }
63: }
