70:   // Example: ``body { string_value: "%PROTOCOL%" }``.
71:   opentelemetry.proto.common.v1.AnyValue body = 2;
72: 
73:   // See 'attributes' in the LogResource proto for more details.
74:   // Example: ``attributes { values { key: "user_agent" value { string_value: "%REQ(USER-AGENT)%" } } }``.
75:   opentelemetry.proto.common.v1.KeyValueList attributes = 3;
76: 
