90:   google.protobuf.Duration buffer_flush_interval = 11;
91: 
92:   // Soft size limit in bytes for the access log buffer. When the buffer exceeds
93:   // this limit, logs will be flushed. Default: 16KB.
94:   google.protobuf.UInt32Value buffer_size_bytes = 12;
95: 
96:   // Additional filter state objects to log as attributes.
97:   repeated string filter_state_objects_to_log = 13;
98: 
99:   // Custom tags to include as log attributes.
100:   repeated type.tracing.v3.CustomTag custom_tags = 14;
